from cryptography.hazmat.primitives.ciphers.aead import AESGCM
import os

def generate_key() -> bytes:
    return os.urandom(32)

def encrypt_message(key: bytes, plaintext: bytes,
                    associated_data: bytes = None) -> tuple:
    aesgcm = AESGCM(key)
    nonce = os.urandom(12)  # 96-bit nonce for GCM
    ciphertext = aesgcm.encrypt(nonce, plaintext, associated_data)
    return nonce, ciphertext

def decrypt_message(key: bytes, nonce: bytes, ciphertext: bytes,
                    associated_data: bytes = None) -> bytes:
    aesgcm = AESGCM(key)
    return aesgcm.decrypt(nonce, ciphertext, associated_data)

from cryptography.hazmat.primitives.ciphers.aead import ChaCha20Poly1305
import os

def chacha_encrypt(key: bytes, plaintext: bytes,
                   aad: bytes = None) -> tuple:
    chacha = ChaCha20Poly1305(key)
    nonce = os.urandom(12)
    ciphertext = chacha.encrypt(nonce, plaintext, aad)
    return nonce, ciphertext

def chacha_decrypt(key: bytes, nonce: bytes, ciphertext: bytes,
                   aad: bytes = None) -> bytes:
    chacha = ChaCha20Poly1305(key)
    return chacha.decrypt(nonce, ciphertext, aad)

def compare_ciphertext_length(plaintext: bytes) -> dict:
    key = os.urandom(32)
    nonce, ciphertext = chacha_encrypt(key, plaintext)
    return {
        'plaintext_len': len(plaintext),
        'ciphertext_len': len(ciphertext),
        'overhead': len(ciphertext) - len(plaintext)
    }

def classical_security(key_bits: int) -> int:
    return key_bits

def quantum_security(key_bits: int) -> int:
    return key_bits // 2

def is_quantum_safe(key_bits: int, min_security: int = 128) -> bool:
    return quantum_security(key_bits) >= min_security

def recommend_key_size(min_security: int = 128) -> int:
    return min_security * 2
